mapper.select:
select tc.id, tc.create_by, tc.update_by, tc.create_time, tc.update_time, tc.delete_flag, tc.enterprise_name, tc.region, tc.establishment_date, tc.registered_capital, tc.paid_in_capital, tc.employee_count, tc.product, tc.website, tc.contact_phone, tc.unified_social_credit_code, tc.legal_representative, tc.address, tc.business_scope, tc.dev_status, tcs_progress.progress from t_enterprise tc left join ( select enterprise_id, progress, row_number() over (partition by enterprise_id order by communication_time desc) as rn from t_enterprise_sub tcs where tcs.delete_flag = 0 ) tcs_progress on tc.id = tcs_progress.enterprise_id and tcs_progress.rn = 1
tc.delete_flag = 0 and tc.enterprise_name like concat('%', #{enterpriseName}, '%') and tc.create_by = #{createBy} and tc.region like concat('%', #{region}, '%') and tc.contact_phone like concat('%', #{contactPhone}, '%') and tc.product like concat('%', #{product}, '%') and tc.dev_status = #{devStatus} AND tc.create_time >= #{params.beginTime} AND tc.create_time <= #{params.endTime}
ORDER BY tc.create_time DESC

