create_by = #{createBy}, update_by = #{updateBy}, create_time = #{createTime}, update_time = #{updateTime}, delete_flag = #{deleteFlag}, enterprise_name = #{enterpriseName}, region = #{region}, establishment_date = #{establishmentDate}, registered_capital = #{registeredCapital}, paid_in_capital = #{paidInCapital}, employee_count = #{employeeCount}, product = #{product}, website = #{website}, contact_phone = #{contactPhone}, data_source = #{dataSource}, status = #{status}, detail = #{detail}, dev_status = #{devStatus},
where id = #{id}

