mapper.select:
WITH idList AS ( SELECT id FROM t_enterprise
delete_flag = 0 and enterprise_name like concat('%', #{enterpriseName}, '%') and region like concat('%', #{region}, '%') and contact_phone like concat('%', #{contactPhone}, '%') and product like concat('%', #{product}, '%') and dev_status = #{devStatus} AND create_time >= #{params.beginTime} AND create_time <= #{params.endTime}
), latest_enterprise_sub AS ( SELECT t1.enterprise_id,t1.progress FROM t_enterprise_sub t1 INNER JOIN ( SELECT enterprise_id, MAX(create_time) as last_create_time FROM t_enterprise_sub WHERE delete_flag = 0 GROUP BY enterprise_id ) t2 ON t1.enterprise_id = t2.enterprise_id AND t1.create_time= t2.last_create_time WHERE t1.delete_flag = 0 )
SELECT st.progress as progress,
FROM t_enterprise LEFT JOIN latest_enterprise_sub as st ON t_enterprise.id = st.enterprise_id WHERE t_enterprise.id in (select id from idList)
